import { takeLatest, put, call, all } from 'redux-saga/effects';
import { signInWithPopup,signInWithEmailAndPassword } from 'firebase/auth';
import { auth, googleProvider, createUserProfileDocument} from '../../firebase/firebase.utils';

import userActionTypes from "../user/user.types";
import  { googleSignInSuccess, googleSignInFailure, emailSignInSuccess, emailSignInFailure } from "../user/user.actions";
import { getDoc } from '@firebase/firestore';

export function* googleSignInAsync () {
    try {
        const { user } = yield signInWithPopup(auth, googleProvider);
        const userRef = yield call(createUserProfileDocument, user);
        const userSnapshot = yield getDoc(userRef);
        yield put(googleSignInSuccess({id: userSnapshot.id, ...userSnapshot.data()}))

    } catch(error) {
        yield put(googleSignInFailure(error));
    }  
}

export function* googleSignInStart (email, password) {
    yield takeLatest(userActionTypes.GOOGLE_SIGNIN_START, googleSignInAsync(email, password));
}

export function* emailSignInAsync ({payload :{email, password}}) {
    try{
        const { user } = yield signInWithEmailAndPassword(email, password, auth);
        const userRef = yield call(createUserProfileDocument, user);
        const userSnapshot = yield getDoc(userRef);
        yield put(emailSignInSuccess({id: userSnapshot.id, ...userSnapshot.data()}))
    }
    catch (error) {
        yield put(emailSignInFailure(error));
    }
}

export function* emailSignInStart () {
    yield takeLatest(userActionTypes.EMAIL_SIGNIN_START, emailSignInAsync)
}

export function* userSagas () {
    yield all([
        call(googleSignInStart),
        call(emailSignInStart)
    ])
}
